75	func (n *Project) Enabled() bool {
76		n.projects = []*ProjectItem{
77			{
78				Name:    nodeToolName,
79				Files:   []string{fileName},
80				Fetcher: n.getNodePackage,
81			},
82			{
83				Name:    denoToolName,
84				Files:   []string{"deno.json", "deno.jsonc"},
85				Fetcher: n.getDenoPackage,
86			},
87			{
88				Name:    "jsr",
89				Files:   []string{"jsr.json", "jsr.jsonc"},
90				Fetcher: n.getJsrPackage,
91			},
92			{
93				Name:    "cargo",
94				Files:   []string{"Cargo.toml"},
95				Fetcher: n.getCargoPackage,
96			},
97			{
98				Name:    pythonToolName,
99				Files:   []string{"pyproject.toml"},
100				Fetcher: n.getPythonPackage,
101			},
102			{
103				Name:    mojoToolName,
104				Files:   []string{"mojoproject.toml"},
105				Fetcher: n.getPythonPackage,
106			},
107			{
108				Name:    phpToolName,
109				Files:   []string{"composer.json"},
110				Fetcher: n.getNodePackage,
111			},
112			{
113				Name:    dartToolName,
114				Files:   []string{"pubspec.yaml"},
115				Fetcher: n.getDartPackage,
116			},
117			{
118				Name:    "nuspec",
119				Files:   []string{"*.nuspec"},
120				Fetcher: n.getNuSpecPackage,
121			},
122			{
123				Name:    dotnetToolName,
124				Files:   []string{"*.sln", "*.slnf", "*.slnx", "*.vbproj", "*.fsproj", "*.csproj"},
125				Fetcher: n.getDotnetProject,
126			},
127			{
128				Name:    juliaToolName,
129				Files:   []string{"JuliaProject.toml", "Project.toml"},
130				Fetcher: n.getProjectData,
131			},
132			{
133				Name:    "lake",
134				Files:   []string{"lakefile.lean", "lakefile.toml"},
135				Fetcher: n.getLakePackage,
136			},
137			{
138				Name:    "powershell",
139				Files:   []string{"*.psd1"},
140				Fetcher: n.getPowerShellModuleData,
141			},
142		}
143	
144		for _, item := range n.projects {
145			// allow files override
146			property := options.Option(fmt.Sprintf("%s_files", item.Name))
147			item.Files = n.options.StringArray(property, item.Files)
148	
149			if !n.hasProjectFile(item) {
150				continue
151			}
152	
153			data := item.Fetcher(*item)
154			if data == nil {
155				continue
156			}
157	
158			n.ProjectData = *data
159			n.Type = item.Name
160			return true
161		}
162	
163		return n.options.Bool(options.AlwaysEnabled, false)
164	}
