174	func (n *Project) getNodePackage(item ProjectItem) *ProjectData {
175		return n.getJSONPackage(item, false)
176	}
177	
178	func (n *Project) getDenoPackage(item ProjectItem) *ProjectData {
179		data := n.getJSONPackage(item, true)
180		if data == nil {
181			return nil
182		}
183	
184		// Deno projects prefer to publish via JSR; merge JSR metadata when available.
185		jsrFile := n.firstExistingFile([]string{"jsr.json", "jsr.jsonc"})
186		if len(jsrFile) == 0 {
187			return data
188		}
189	
190		jsrData, err := n.parseJSONPackage(jsrFile, true)
191		if err != nil {
192			log.Error(err)
193			return data
194		}
195	
196		if len(jsrData.Version) != 0 {
197			data.Version = jsrData.Version
198		}
199	
200		if len(jsrData.Name) != 0 {
201			data.Name = jsrData.Name
202		}
203	
204		return data
205	}
206	
207	func (n *Project) getJsrPackage(item ProjectItem) *ProjectData {
208		return n.getJSONPackage(item, true)
209	}
