211	func (n *Project) getCargoPackage(item ProjectItem) *ProjectData {
212		content := n.env.FileContent(item.Files[0])
213	
214		var data CargoTOML
215		err := toml.Unmarshal([]byte(content), &data)
216		if err != nil {
217			n.Error = err.Error()
218			return nil
219		}
220	
221		return &ProjectData{
222			Version: data.Package.Version,
223			Name:    data.Package.Name,
224		}
225	}
226	
227	func (n *Project) getPythonPackage(item ProjectItem) *ProjectData {
228		content := n.env.FileContent(item.Files[0])
229	
230		var data PyProjectTOML
231		err := toml.Unmarshal([]byte(content), &data)
232		if err != nil {
233			n.Error = err.Error()
234			return nil
235		}
236	
237		if len(data.Tool.Poetry.Version) != 0 || len(data.Tool.Poetry.Name) != 0 {
238			return &ProjectData{
239				Version: data.Tool.Poetry.Version,
240				Name:    data.Tool.Poetry.Name,
241			}
242		}
243		return &ProjectData{
244			Version: data.Project.Version,
245			Name:    data.Project.Name,
246		}
247	}
248	
249	func (n *Project) getDartPackage(item ProjectItem) *ProjectData {
250		content := n.env.FileContent(item.Files[0])
251		var data ProjectData
252		err := yaml.Unmarshal([]byte(content), &data)
253		if err != nil {
254			n.Error = err.Error()
255			return nil
256		}
257	
258		return &data
259	}
260	
261	func (n *Project) getNuSpecPackage(_ ProjectItem) *ProjectData {
262		files := n.env.LsDir(n.env.Pwd())
263		var content string
264		// get the first match only
265		for _, file := range files {
266			if filepath.Ext(file.Name()) == ".nuspec" {
267				content = n.env.FileContent(file.Name())
268				break
269			}
270		}
271	
272		var data NuSpec
273		err := xml.Unmarshal([]byte(content), &data)
274		if err != nil {
275			n.Error = err.Error()
276			return nil
277		}
278	
279		return &ProjectData{
280			Version: data.MetaData.Version,
281			Name:    data.MetaData.Title,
282		}
283	}
284	
285	func (n *Project) getDotnetProject(item ProjectItem) *ProjectData {
286		var name string
287		var content string
288		var extension string
289	
290		files := n.env.LsDir(n.env.Pwd())
291	
292		extensions := make([]string, len(item.Files))
293		for i, file := range item.Files {
294			// Remove leading * and keep only the extension
295			extensions[i] = strings.TrimPrefix(file, "*")
296		}
297	
298		// get the first match only
299		for _, file := range files {
300			extension = filepath.Ext(file.Name())
301			if slices.Contains(extensions, extension) {
302				name = strings.TrimSuffix(file.Name(), filepath.Ext(file.Name()))
303				content = n.env.FileContent(file.Name())
304				break
305			}
306		}
307	
308		// the name of the parameter may differ depending on the version,
309		// so instead of xml.Unmarshal() we use regex:
310		var target string
311		tag := "(?P<TAG><.*TargetFramework.*>(?P<TFM>.*)</.*TargetFramework.*>)"
312	
313		values := regex.FindNamedRegexMatch(tag, content)
314		if len(values) != 0 {
315			target = values["TFM"]
316		}
317	
318		if target == "" && (extension == ".sln" || extension == ".slnx") && n.options.Bool(ResolveTargetFromSolution, true) {
319			maxDepth := n.options.Int(SolutionSearchDepth, 2)
320			if projContent := n.findProjectFile(files, maxDepth); projContent != "" {
321				values = regex.FindNamedRegexMatch(tag, projContent)
322				if len(values) != 0 {
323					target = values["TFM"]
324				}
325			}
326		}
327	
328		if target == "" {
329			log.Error(fmt.Errorf("cannot extract TFM from %s project file", name))
330		}
331	
332		return &ProjectData{
333			Target: target,
334			Name:   name,
335		}
336	}
337	
338	// findProjectFile scans rootEntries and their subdirectories breadth-first,
339	// up to maxDepth levels deep, and returns the content of the first
340	// .csproj/.fsproj/.vbproj file found. Paths are kept relative to pwd so
341	// FileContent resolves them the same way the caller does.
342	func (n *Project) findProjectFile(rootEntries []fs.DirEntry, maxDepth int) string {
343		projectExts := []string{".csproj", ".fsproj", ".vbproj"}
344		pwd := n.env.Pwd()
345	
346		var dirs []string
347		for _, entry := range rootEntries {
348			if entry.IsDir() {
349				dirs = append(dirs, entry.Name())
350				continue
351			}
352	
353			// a project file can live next to the solution
354			if slices.Contains(projectExts, filepath.Ext(entry.Name())) {
355				return n.env.FileContent(entry.Name())
356			}
357		}
358	
359		for depth := 1; depth <= maxDepth && len(dirs) > 0; depth++ {
360			var next []string
361	
362			for _, dir := range dirs {
363				for _, entry := range n.env.LsDir(filepath.Join(pwd, dir)) {
364					if entry.IsDir() {
365						next = append(next, filepath.Join(dir, entry.Name()))
366						continue
367					}
368	
369					if slices.Contains(projectExts, filepath.Ext(entry.Name())) {
370						return n.env.FileContent(filepath.Join(dir, entry.Name()))
371					}
372				}
373			}
374	
375			dirs = next
376		}
377	
378		return ""
379	}
380	
381	func (n *Project) getPowerShellModuleData(_ ProjectItem) *ProjectData {
382		files := n.env.LsDir(n.env.Pwd())
383		var content string
384		// get the first match only
385		// excluding PSScriptAnalyzerSettings.psd1
386		for _, file := range files {
387			if filepath.Ext(file.Name()) == ".psd1" && file.Name() != "PSScriptAnalyzerSettings.psd1" {
388				content = n.env.FileContent(file.Name())
389				break
390			}
391		}
392	
393		if content == "" {
394			return nil
395		}
396	
397		data := &ProjectData{}
398		lines := strings.SplitSeq(content, "\n")
399	
400		for line := range lines {
401			key, value, found := strings.Cut(line, "=")
402			if !found {
403				continue
404			}
405			key = strings.TrimSpace(key)
406			value = strings.TrimSpace(value)
407			value = strings.Trim(value, "'\"")
408	
409			switch key {
410			case "ModuleVersion":
411				data.Version = value
412			case "RootModule":
413				data.Name = strings.TrimRight(value, ".psm1")
414			}
415		}
416	
417		return data
418	}
419	
420	func (n *Project) getLakePackage(item ProjectItem) *ProjectData {
421		file := n.firstExistingFile(item.Files)
422		if len(file) == 0 {
423			return nil
424		}
425	
426		if strings.HasSuffix(file, ".lean") {
427			return n.getLakeLeanPackage(file)
428		}
429	
430		return n.getLakeTomlPackage(file)
431	}
432	
433	func (n *Project) getLakeLeanPackage(file string) *ProjectData {
434		content := n.env.FileContent(file)
435	
436		match := regex.FindNamedRegexMatch(`package\s+(?P<NAME>.+?)\s+where`, content)
437		name, ok := match["NAME"]
438		if !ok || len(name) == 0 {
439			return nil
440		}
441	
442		// Strip guillemets (« U+00AB and » U+00BB) if present
443		name = strings.Trim(name, "\u00AB\u00BB")
444	
445		return &ProjectData{
446			Name: strings.TrimSpace(name),
447		}
448	}
449	
450	func (n *Project) getLakeTomlPackage(file string) *ProjectData {
451		content := n.env.FileContent(file)
452	
453		var data LakeFileTOML
454		err := toml.Unmarshal([]byte(content), &data)
455		if err != nil {
456			n.Error = err.Error()
457			return nil
458		}
459	
460		return &ProjectData{
461			Name: data.Name,
462		}
463	}
464	
465	func (n *Project) getProjectData(item ProjectItem) *ProjectData {
466		content := n.env.FileContent(item.Files[0])
467	
468		var data ProjectData
469		err := toml.Unmarshal([]byte(content), &data)
470		if err != nil {
471			n.Error = err.Error()
472			return nil
473		}
474	
475		return &data
476	}
477	
478	func (n *Project) getJSONPackage(item ProjectItem, allowJSONC bool) *ProjectData {
479		file := n.firstExistingFile(item.Files)
480		if len(file) == 0 {
481			return nil
482		}
483	
484		data, err := n.parseJSONPackage(file, allowJSONC)
485		if err != nil {
486			n.Error = err.Error()
487			return nil
488		}
489	
490		return data
491	}
492	
493	func (n *Project) firstExistingFile(files []string) string {
494		for _, file := range files {
495			if !n.env.HasFiles(file) {
496				continue
497			}
498			return file
499		}
500	
501		return ""
502	}
503	
504	func (n *Project) parseJSONPackage(file string, allowJSONC bool) (*ProjectData, error) {
505		content := n.env.FileContent(file)
506		if allowJSONC && filepath.Ext(file) == ".jsonc" {
507			content = jsonutil.StripComments(content)
508		}
509	
510		var data ProjectData
511		err := json.Unmarshal([]byte(content), &data)
512		if err != nil {
513			return nil, err
514		}
515	
516		return &data, nil
517	}
